import LocalErrorBoundary from "../LocalErrorBoundary";
import { createRoot } from "react-dom/client";
import {MatchTiming} from "ftc-common/javaTypes";
import MatchButtons from "../matchButtons/MatchButtons";
import {parseMatchTiming} from "ftc-common/utils";
declare global {
    interface Window {
        field: number
        fieldCount: number
        eventCode: string
        hrControl: string
        isDivision: boolean
        isParent: boolean
        division: number
        divisions?: string[]
        penaltyTabletEnabled: boolean
        matchTiming: MatchTiming
        eventType: string
    }
}

const container = document.getElementById('matchButtonsContent');
if (!container) {
    console.error("Mount point for match buttons container not found")
} else {
    const root = createRoot(container);
    root.render(<LocalErrorBoundary>
        <MatchButtons field={window.field} eventCode={window.eventCode} fieldCount={window.fieldCount} controlSettings={window.hrControl} timing={parseMatchTiming(window.matchTiming)} eventType={window.eventType} />
    </LocalErrorBoundary>);
}
